import os

def delete_file(filename):
    # Check if the filename is valid and does not contain any path traversal attacks
    if ".." in filename or "/" in filename:
        return False
    
    # Build the filepath for the uploads directory
    filepath = os.path.join("uploads", filename)
    
    # Delete the file if it exists
    if os.path.exists(filepath):
        os.remove(filepath)
        return True
    else:
        return False